def write_locale(locale: str, overrides: dict[str, str]) -> None:
    data = {"@@locale": locale}
    merged = BASE | overrides
    for key in BASE:
        data[key] = merged[key]
        if locale == "en" and key in META:
            data[f"@{key}"] = META[key]
    (L10N_DIR / f"app_{locale}.arb").write_text(
        json.dumps(data, ensure_ascii=False, indent=2) + "\n",
        encoding="utf-8",
    )


def main() -> None:
    L10N_DIR.mkdir(parents=True, exist_ok=True)
    write_locale("en", {})
    for locale, overrides in LOCALES.items():
        write_locale(locale, overrides)
    print(f"Wrote {1 + len(LOCALES)} locale files with {len(BASE)} messages each.")


if __name__ == "__main__":
    main()
